import random
import textwrap

# Sample tech articles
articles = [
    {
        "title": "AI Revolutionizes Healthcare",
        "content": "Recent advancements in artificial intelligence are transforming healthcare with more accurate diagnoses and personalized treatment plans."
    },
    {
        "title": "Quantum Computing Takes a Leap Forward",
        "content": "Scientists have made significant progress in quantum computing, bringing us closer to solving complex problems that classical computers can't handle."
    },
    {
        "title": "5G Networks: The Future of Connectivity",
        "content": "The rollout of 5G networks is set to revolutionize connectivity, offering faster speeds and supporting new technologies like autonomous vehicles."
    },
    {
        "title": "Blockchain Security Enhancements",
        "content": "Blockchain technology is improving its security features, making it a more reliable solution for financial transactions and beyond."
    },
    {
        "title": "Cybersecurity: A Growing Concern",
        "content": "As technology advances, so do cyber threats. Companies are investing in robust cybersecurity measures to protect sensitive data."
    }
]

# Function to generate a summary from the articles
def generate_news_brief(articles):
    print("Today's Tech News Brief:\n")
    for article in articles:
        title = article["title"]
        content = article["content"]
        summary = textwrap.shorten(content, width=80, placeholder="...")
        print(f"Title: {title}\nSummary: {summary}\n")

# Main function to run the program
def main():
    # Clear the terminal
    print('\033[2J\033[H', end='')
    
    # Generate and print the news brief
    generate_news_brief(articles)

# Run the program
if __name__ == "__main__":
    main()